var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흠, 흐흠~","JPN":"ふん、ふふん～","ENG":"Hm... Hmm...","TWN":"哼哼哼～"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"예쁜 보물. 아버지가 좋아하실 거야.","JPN":"キレイなお宝。お父様が喜ぶわ。","ENG":"Ooh, pretty treasure. Father will love it.","TWN":"美麗的寶物，父親一定會很喜歡的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"멈춰라!","JPN":"止まれ！","ENG":"Stop!","TWN":"住手！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"여긴 나나하라 영지다. 외부인이 어떻게 여기까지 들어온 거지?","JPN":"ここは七原の領地だ。よそ者がどうやってここまで入ってきたんだ？","ENG":"This is Nanahara territory. How did you get in here?","TWN":"這裡是七原領地，外人是怎麼進到這裡的？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그건 말이죠~ 심부름을 받아서 물건을 좀 가지러 왔어요~","JPN":"それはですね～おつかいで物を取りに来たんです～","ENG":"Well, if you really want to know... I'm here on an errand to get something!","TWN":"這個嘛～我是奉命來拿點東西的～"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"잠깐?","JPN":"ちょっと待て。","ENG":"Wait.","TWN":"等等？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"그건 결계옥이잖아? 신기의 위치는 당주와 무사님만이 알고 계실 텐데?","JPN":"それは結界玉じゃないか？　神器の位置はご当主とお侍様だけが知っておられるはずだ。","ENG":"That's Akaitama. But only Lady Nanahara and Miss Chifuyu know of its location...","TWN":"那不是結界玉石嗎？神器的位置應該只有堂主和武士大人知道才對。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"맞아요. 당주님이 저에게 이걸 가져오라고 시켰거든요.","JPN":"そうなんです。ご当主が私にこれを持ってくるようにとおっしゃって。","ENG":"You're right. Lady Nanahara asked me to fetch it for her.","TWN":"沒錯，就是堂主叫我來拿的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"웃기지 마라, 침입자. 결계옥은 영지에서 함부로 옮겨져선 안 돼.","JPN":"ふざけるな、侵入者。結界玉は領地から搬出されてはならない。","ENG":"Don't make me laugh, intruder. Akaitama is not to be moved even within our territory.","TWN":"胡說八道！入侵者，結界玉石是不能隨意離開領地的，"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"그걸 누구보다 잘 아는 당주님께서 그런 말씀을 하실 리 없다.","JPN":"それを誰よりもよくご存じのご当主がそんな命令をするわけがない。","ENG":"There is no way Lady Nanahara would ask you to do something like that.","TWN":"堂主明知道這一點，怎麼可能還叫你來拿。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"후후, 실은 말이지. 다 알고 있어.","JPN":"ふふ、実はね。全部知ってるの。","ENG":"Hah hah. Well, the truth is... I know everything.","TWN":"呵呵，其實我全都知道。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네가 안 믿을 거란 것도, 그 총구를 겨눌 거란 것도,","JPN":"お前が信じないってことも、その銃で私を狙うことも、","ENG":"I know you don't believe me, and that you're going to aim that gun on me too.","TWN":"我知道你不會相信，我也知道槍口會瞄準我。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"……그리고 호주머니의 스위치를 몰래 눌러 사람들을 호출할 거란 사실도.","JPN":"……そしてポケットのスイッチをこっそり押して人を呼び出すってこともね。","ENG":"Also... I know that you would press that switch in your pocket to call for reinforcements.","TWN":"……我還知道你會偷偷按下口袋裡的開關呼叫支援。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"……뭣? 그걸 어떻게?","JPN":"……なっ？　それをどうやって？","ENG":"...What?! H-how?","TWN":"……什麼？你是怎麼知道的？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지는 늘 작은 위험도 배제하라고 하셨어.","JPN":"お父様はいつも小さな危険であっても排除しろとおっしゃるわ。","ENG":"Father always told me to mind the small risks.","TWN":"父親總是告誡我絕對不要冒險。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"하지만 그거 알아?","JPN":"でも、知ってる？","ENG":"But you know what?","TWN":"但你知道嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"내가 알고 있는 것들이 현실로 이루어질 때의 쾌감은…… 정말 짜릿하거든.","JPN":"私が知っていることが現実になる時の快感って……本当に刺激的なのよ。","ENG":"The pleasure of seeing what I foresee come true... It's exhilarating.","TWN":"當我知道的與現實吻合時，那個快感……有多爽！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"결국 그 모든 부질없는 저항 끝에 죽어갈 녀석들의 발버둥을 보고 있으면……","JPN":"全力で無駄な抵抗をしても結局は死んでいく、そんなやつらの足掻いている姿を見てると……","ENG":"Seeing them struggle and die in the end... knowing that resistance is futile...","TWN":"看到你們盡全力抵抗，但終究還是難逃一死時……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"……정말 참을 수 없을 정도로 기분이 좋아져.","JPN":"……本当にたまらなく気持ちいいわ。","ENG":"...It makes me so happy inside.","TWN":"……我真的感到無比的快樂！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"이, 이런……!","JPN":"く、くそ……！","ENG":"A-argh...!","TWN":"你…可惡……！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아아, 당주 녀석이 같은 능력을 가지고 있다고 해서 살짝 긴장했는데……","JPN":"ああ、当主のやつが同じ能力を持っているっていうから、ちょっと緊張してたのに……","ENG":"Aah... I was a little nervous because that leader of yours has the same ability as me...","TWN":"對了，我聽說堂主那傢伙也有相同的能力，害我還有點緊張呢……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"내가 여기에 올 거라는 것도 예측 못 하다니. 김 빠져.","JPN":"私がここに来るってことも予測できないなんてね。気が抜けちゃった。","ENG":"But she couldn't even predict that I would be here. This is no fun at all.","TWN":"但她竟然連我會來這裡沒有預料到，真是掃興。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"맞혔나?","JPN":"命中したか？","ENG":"Did we get her?","TWN":"有打到嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L46_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……아닌 것 같군요.","JPN":"……違うようですね。","ENG":"...I am afraid not.","TWN":"……好像沒有。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"쳇, 기습했는데도 막아낸 건가?","JPN":"ちっ、不意打ちしたのに防げたのか？","ENG":"Tch! Our ambush didn't work?","TWN":"嘖，用偷襲的還是被她閃掉嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"고작 너희 둘만으로 날 어떻게 해보려고?","JPN":"お前たち二人だけでやるつもり？","ENG":"How are you two gonna try and stop me?","TWN":"就憑你們二個是能拿我怎麼辦？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……그걸 내려놔라.","JPN":"……それを置け。","ENG":"...Put that done.","TWN":"……把東西交出來。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결계옥을 영지 밖으로 가져가면, 결계가 무너져 현실에 돌이킬 수 없는 피해를 주게 된다.","JPN":"結界玉を領地の外へ持ち出すと、結界が崩れ現実に取り返しのつかない被害を与えることになる。","ENG":"If you take that out of here, the barrier will fall and cause irreversible devastation.","TWN":"結界玉石要是離開領地，結界瓦解會對現世造成無法挽回的傷害。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"알아. 하지만 아버지께서 원하시거든.","JPN":"知ってるわ。でもお父様がほしがってるから。","ENG":"I know. But father wants it.","TWN":"我知道，但這是父親要的。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"알긴 뭘 알아?! 하나도 모르는구만!","JPN":"何が知ってるじゃ！　何も知らんくせに！","ENG":"No, you don't! You don't know anything!","TWN":"你知道個什麼鬼？你根本一無所知！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이곳 나나하라 영지는 과거 역신으로 인해 무너진 옛 세계를 지키는 경계다.","JPN":"この七原領地は過去疫病神により崩れた、かつての世界を守る境界なんじゃ。","ENG":"The Nanahara territory is the frontier of where the old world collapsed by the Plague God.","TWN":"七原領地是守護以前因瘟神而瓦解的舊世界的分界。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"영지의 결계가 허물어지면 그 이면세계가 현실을 침범하고 만다고!","JPN":"領地の結界が崩れればその裏世界が現実を侵すことになってしまうのだぞ！","ENG":"If the barrier is broken, Counterside will seep into reality!","TWN":"領地的結界要是瓦解，異界就會侵犯現世！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네 녀석…… 세상이 어떻게 돼도 상관없구만?","JPN":"お主……世界がどうなってもいいのじゃな？","ENG":"Girl... You don't care what happens to the world, do you?","TWN":"你這傢伙……一點也不在乎世界會變成怎麼樣嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지원 부탁드리겠습니다, 나오님.","JPN":"支援をお願いいたします、ナオ様。","ENG":"I request your assistance, Miss Nao.","TWN":"奈緒大人，我需要您的幫忙。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"만만한 놈이 아니다. 살려서 붙잡는다거나 그런 무리한 요구는 하지 마.","JPN":"ただ者ではない。生きたままとらえろとかそんな無茶なことは言うなよ。","ENG":"Don't underestimate her. And don't expect me to capture her alive.","TWN":"那丫頭不好對付，不准提出無理的要求，像是要活捉她之類的。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어머, 진심으로 해보려고?","JPN":"あら、本気でやるの？","ENG":"Oh? Are you going to take me on for real?","TWN":"哇喔，現在是要來真的嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그럼 얼마나 버티나 한 번 볼까?","JPN":"じゃあ、どれだけ耐えられるか見てみようかしら。","ENG":"Then let's see how long you'll last.","TWN":"那就來看看你們可以撐多久囉？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};